(self.webpackChunkcheatsheet=self.webpackChunkcheatsheet||[]).push([[1365],{1496:(n,e,s)=>{"use strict";s.r(e),s.d(e,{data:()=>a});const a={key:"v-7d0d1486",path:"/python/error/error-type/runtime/",title:"Runtime Error",lang:"en-US",frontmatter:{},excerpt:"",headers:[{level:2,title:"การเก็บข้อมูลเข้าตัวแปร",slug:"การเก็บข้อมูลเข้าตัวแปร",children:[{level:3,title:"Introduction to is keyword",slug:"introduction-to-is-keyword",children:[]}]}],filePathRelative:"python/error/error-type/runtime/README.md",git:{updatedTime:162676698e4,contributors:[]}}},3845:(n,e,s)=>{"use strict";s.r(e),s.d(e,{default:()=>t});var a=s(6252);const r=(0,a.uE)('<h1 id="runtime-error" tabindex="-1"><a class="header-anchor" href="#runtime-error" aria-hidden="true">#</a> Runtime Error</h1><h2 id="การเก็บข้อมูลเข้าตัวแปร" tabindex="-1"><a class="header-anchor" href="#การเก็บข้อมูลเข้าตัวแปร" aria-hidden="true">#</a> การเก็บข้อมูลเข้าตัวแปร</h2><p>ต้องอธิบายก่อนว่า ปกติแล้ว Python จะทำการใช้พื้นที่ให้น้อยที่สุด เพื่อให้มันไม่หนักเครื่องและประหยัดทรัพยากร และถ้าจำเป็นที่จะต้องไปขอพื้นที่เพื่ม ก็จะไปขอให้ แต่ก็ต้องเพราะว่า มันจำเป็นนั่นเอง</p><p>โดยหลักการลดพิ้นที่จัดเก็บนั้น ก็ได้เข้ามาสู่ตัวแปรครับ<br> เพื่อที่จะให้ Python ทำการใช้ข้อมูลจัดเก็บให้น้อยที่สุด Python จะทำการรวมตัวแปร เช่น</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>var1 <span class="token operator">=</span> <span class="token string">&quot;Kuma&quot;</span>\nvar1 <span class="token operator">=</span> var2\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>หากว่าน้องๆทำการเทียบด้วย <code>==</code> แล้ว</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>var1 <span class="token operator">==</span> var2\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>ก็จะได้ออกมาเป็น <code>True</code> เพราะมันอันเดียวกันเลย พอเวลาเรียกเบอร์ใน memory (เหมือนเบอร์ตู้ locker) ก็จะบอกเบอร์เดียวกัน ทำให้ไม่ต้องไปเปิด locker อีก</p><p>และยังย่อไม่พอครับ แบบนี้เค้าก็ย่อได้นะ</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>var1 <span class="token operator">=</span> <span class="token string">&quot;Kuma&quot;</span>\nvar2 <span class="token operator">=</span> <span class="token string">&quot;Kuma&quot;</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>หากว่าน้องๆทำการเทียบด้วย <code>==</code> แล้ว</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>var1 <span class="token operator">==</span> var2\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>ก็จะออกมาเป็น True เพราะ Python ตอนที่ Analyze code ก็จะทำการให้มันเก็บเข้าไปในเบอร์เดียวกัน เหมือน อันแรกเลยจ้า</p><p>แต่ว่า อันนี้ก็จะไม่ใช่แล้วแหละ</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>var1 <span class="token operator">=</span> <span class="token string">&#39;a&#39;</span> <span class="token operator">*</span> <span class="token number">100</span>\nvar2 <span class="token operator">=</span> <span class="token string">&#39;a&#39;</span> <span class="token operator">*</span> <span class="token number">100</span>\n\n<span class="token keyword">print</span><span class="token punctuation">(</span>var1 <span class="token operator">==</span> var2<span class="token punctuation">)</span>\n<span class="token keyword">print</span><span class="token punctuation">(</span>var1 <span class="token keyword">is</span> var2<span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>ผลลัพท์ก็จะออกมาดังนี้ครับ</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>True\nFalse\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>ถ้าน้องยังงงหลักการ หรือไม่รู้ว่า is คืออะไร ให้ไปอ่านข้างล่างก่อนครับ แล้วค่อยมาอ่านต่อ</p><p>น้องๆก็จะเห็นว่า <code>is</code> ไม่ได้ค่าเท่ากับ <code>==</code> เลย เพราะว่า Python เลือกที่จะเก็บข้อมูลคนละที่กัน ทำให้ผลลัพท์เป็นเท็จนี่เอง</p><h3 id="introduction-to-is-keyword" tabindex="-1"><a class="header-anchor" href="#introduction-to-is-keyword" aria-hidden="true">#</a> Introduction to <code>is</code> keyword</h3><p>โดยหลักการของ <code>is</code> นั่นก็คือ หากว่ามันคืออันเดียวกัน เก็บข้อมูลใน Memory address เดียวกันด้วย ก็จะตอบลกลับมาว่า True</p><p>ความแตกต่างระหว่าง <code>==</code> และ <code>is</code> ก็จะเป็นเรื่องของที่อยู่จัดเก็บ (Memory Address) ที่ต้องเป็นอันเดียวกันด้วยนั่นเอง</p><p>เช่น</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>var1 <span class="token operator">=</span> <span class="token string">&quot;Kuma&quot;</span>\nvar2 <span class="token operator">=</span> var1\n\n<span class="token keyword">print</span><span class="token punctuation">(</span>var1 <span class="token keyword">is</span> var2<span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>ก็จะออกผลลัพท์มาเป็น True นั่นเอง เพราะการทำบรรทัดที่ 2 นั่น ไม่ใช้แค่ตัวแปร <code>var2</code> จะก้อปปี้ string แล้ว ก็ยังก้อปปี้ address ด้วยครับ</p><hr><p>Reference</p>',27),o={href:"https://softwareengineering.stackexchange.com/questions/313254/how-does-the-python-runtime-actually-work",target:"_blank",rel:"noopener noreferrer"},p=(0,a.Uk)("softwareengineering.stackexchange.com/questions/313254/how-does-the-python-runtime-actually-work"),t={render:function(n,e){const s=(0,a.up)("OutboundLink");return(0,a.wg)(),(0,a.j4)(a.HY,null,[r,(0,a.Wm)("ul",null,[(0,a.Wm)("li",null,[(0,a.Wm)("a",o,[p,(0,a.Wm)(s)])])])],64)}}}}]);